import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"@karpathy — AI 輸入偏好音訊、輸出偏好視覺；HTML 是當前最佳輸出格式升級路徑","description":"","frontmatter":{"title":"@karpathy — AI 輸入偏好音訊、輸出偏好視覺；HTML 是當前最佳輸出格式升級路徑","author":"@karpathy（Andrej Karpathy｜2,438,416 followers）","date":"2026-05-11T00:00:00.000Z","source":"https://x.com/karpathy/status/2053872850101285137","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-11-@karpathy-285137.md","filePath":"research/tweets/2026-05-11-@karpathy-285137.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-05-11-@karpathy-285137.md"};function n(s,t,l,h,d,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="karpathy-—-ai-輸入偏好音訊、輸出偏好視覺-html-是當前最佳輸出格式升級路徑" tabindex="-1">@karpathy — AI 輸入偏好音訊、輸出偏好視覺；HTML 是當前最佳輸出格式升級路徑 <a class="header-anchor" href="#karpathy-—-ai-輸入偏好音訊、輸出偏好視覺-html-是當前最佳輸出格式升級路徑" aria-label="Permalink to &quot;@karpathy — AI 輸入偏好音訊、輸出偏好視覺；HTML 是當前最佳輸出格式升級路徑&quot;">​</a></h1><p><strong>來源</strong>: <a href="https://x.com/karpathy/status/2053872850101285137" target="_blank" rel="noreferrer">https://x.com/karpathy/status/2053872850101285137</a><br><strong>作者</strong>: @karpathy（Andrej Karpathy｜2,438,416 followers）<br><strong>日期</strong>: 2026-05-11<br><strong>統計</strong>: 👍 16,152 · 🔁 1,661 · 🔖 18,554 · 👁 2,073,189<br><strong>收錄</strong>: 2026-05-13 · <strong>評分: 6.9 / 10</strong><br><strong>整合決策</strong>: Rule（<code>ask-for-html-output</code>）</p><hr><h2 id="原文全文" tabindex="-1">原文全文 <a class="header-anchor" href="#原文全文" aria-label="Permalink to &quot;原文全文&quot;">​</a></h2><p>This works really well btw, at the end of your query ask your LLM to &quot;structure your response as HTML&quot;, then view the generated file in your browser. I&#39;ve also had some success asking the LLM to present its output as slideshows, etc.</p><p>More generally, imo audio is the human-preferred input to AIs but vision (images/animations/video) is the preferred output from them. Around a ~third of our brains are a massively parallel processor dedicated to vision, it is the 10-lane superhighway of information into brain. As AI improves, I think we&#39;ll see a progression that takes advantage:</p><ol><li>raw text (hard/effortful to read)</li><li>markdown (bold, italic, headings, tables, a bit easier on the eyes) &lt;-- current default</li><li>HTML (still procedural with underlying code, but a lot more flexibility on the graphics, layout, even interactivity) &lt;-- early but forming new good default ...4,5,6,... n) interactive neural videos/simulations</li></ol><p>Imo the extrapolation (though the technology doesn&#39;t exist just yet) ends in some kind of interactive videos generated directly by a diffusion neural net. Many open questions as to how exact/procedural &quot;Software 1.0&quot; artifacts (e.g. interactive simulations) may be woven together with neural artifacts (diffusion grids), but generally something in the direction of the recently viral <a href="https://x.com/zan2434/status/2046982383430496444" target="_blank" rel="noreferrer">https://x.com/zan2434/status/2046982383430496444</a></p><p>There are also improvements necessary and pending at the input. Audio nor text nor video alone are not enough, e.g. I feel a need to point/gesture to things on the screen, similar to all the things you would do with a person physically next to you and your computer screen.</p><p>TLDR The input/output mind meld between humans and AIs is ongoing and there is a lot of work to do and significant progress to be made, way before jumping all the way into neuralink-esque BCIs and all that. For what&#39;s worth exploring at the current stage, hot tip try ask for HTML.</p><hr><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>音訊是人類對 AI 的偏好輸入，視覺是 AI 的偏好輸出；當下立即可行的行動是在 prompt 末段要求 LLM 回傳 HTML。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>輸入/輸出非對稱框架</strong>：人類偏好用音訊輸入（低阻力），AI 偏好輸出視覺（腦 1/3 是視覺處理器，10 車道資訊高速公路）</li><li><strong>輸出格式演進路徑</strong>：raw text → markdown → HTML → 互動神經影片/模擬；當前應跨越到 HTML</li><li><strong>輸入仍待突破</strong>：純音訊/文字/影片不夠，需要手勢/指向能力（類似面對面互動）——BCI 是終點但非近期目標</li></ol><h3 id="關鍵工具-引用" tabindex="-1">關鍵工具/引用 <a class="header-anchor" href="#關鍵工具-引用" aria-label="Permalink to &quot;關鍵工具/引用&quot;">​</a></h3><ul><li>神經科學援引：視覺佔大腦 1/3 處理能力</li><li>參考案例：@zan2434 的互動視覺化工具（viral）</li><li>立即可行 prompt：在查詢末段加「structure your response as HTML」</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li>HTML 建議高度可行、立即可試，是本推文最有價值的 actionable tip</li><li>「interactive neural video」外推缺乏技術支撐，神經科學論據停留在科普層級，無 benchmark 佐證</li><li>HTML 安全問題（本地執行惡意 HTML、XSS）完全未提，使用者需自行注意執行環境</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A 可行動性 (30%)</td><td>8</td><td>一行 prompt 即可試驗，立即可行</td></tr><tr><td>B 創新性 (20%)</td><td>7</td><td>輸入/輸出非對稱框架有洞見，但 HTML 技巧早有傳播</td></tr><tr><td>C 證據品質 (20%)</td><td>5</td><td>神經科學援引科普級；無 A/B 資料</td></tr><tr><td>D 技術深度 (15%)</td><td>6</td><td>點到為止；無實作細節</td></tr><tr><td>E 泛化性 (15%)</td><td>8</td><td>框架適用任何 LLM 使用場景</td></tr></tbody></table><p><strong>加權總分</strong>: 8×0.3 + 7×0.2 + 5×0.2 + 6×0.15 + 8×0.15 = <strong>6.9</strong></p>',24)])])}const g=e(i,[["render",n]]);export{c as __pageData,g as default};
